import{_ as a,c as n,o as e,ag as p}from"./chunks/framework.QPV3Ar9-.js";const l="/assets/agent0.CfOi1y0_.png",i="/assets/agent1.B3mvgfB2.png",t="/assets/agent2.DH-1h9GP.png",o="/assets/agent3.CBfCJ_DV.png",c="/assets/agent4.BEG_w41m.png",r="/assets/agent7.BQIWOUed.jpeg",d="/assets/agent5.K3I0SIuf.png",u="/assets/agent6.Hj3aLwzs.png",m="/assets/gpu1.BqYtvfhm.jpeg",g="/assets/gpu2.Ctk8v8IU.jpeg",b="/assets/gpu3.DsMLQ_4f.jpg",S=JSON.parse('{"title":"自定义","description":"","frontmatter":{"outline":"deep","head":[["link",{"rel":"canonical","href":"https://www.spiritlhl.net/guide/oneclickvirt/oneclickvirt_custom.html"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:site_name","content":"一键虚拟化项目"}],["meta",{"property":"og:locale","content":"zh_CN"}],["meta",{"property":"og:title","content":"自定义"}],["meta",{"property":"og:url","content":"https://www.spiritlhl.net/guide/oneclickvirt/oneclickvirt_custom.html"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"自定义"}]]},"headers":[],"relativePath":"guide/oneclickvirt/oneclickvirt_custom.md","filePath":"guide/oneclickvirt/oneclickvirt_custom.md","lastUpdated":1780885577000}'),h={name:"guide/oneclickvirt/oneclickvirt_custom.md"};function _(P,s,k,v,f,I){return e(),n("div",null,s[0]||(s[0]=[p('<h1 id="自定义" tabindex="-1">自定义 <a class="header-anchor" href="#自定义" aria-label="Permalink to &quot;自定义&quot;">​</a></h1><h2 id="使用agent模式纳管无独立公网ipv4地址的节点" tabindex="-1">使用agent模式纳管无独立公网IPV4地址的节点 <a class="header-anchor" href="#使用agent模式纳管无独立公网ipv4地址的节点" aria-label="Permalink to &quot;使用agent模式纳管无独立公网IPV4地址的节点&quot;">​</a></h2><p>对于一些本地设备，虽然具备 IPv4 公网访问能力，但由于没有固定或动态的独立 IPv4 地址，因此无法通过标准模式使用 SSH 直接纳管节点。针对这类场景，现提供一种新的纳管方式 —— <strong>Agent 模式</strong>。</p><p><img src="'+l+'" alt="" loading="lazy"></p><p>新增节点时，点击对应的 <strong>Agent 模式</strong> 后，将进入基础信息配置页面。</p><p><img src="'+i+'" alt="" loading="lazy"></p><p>与常规的标准模式不同，Agent 模式下：</p><ul><li><code>IP 地址</code></li><li><code>端口</code></li></ul><p>这两项不再为必填项，即使留空也可以正常纳管节点。</p><p><strong>本地节点 / 家宽节点 / NAT 网络环境节点</strong> 不要填写 IP 地址和端口，保持留空即可。</p><p><strong>云服务器 / 有固定 IPv4 的服务器</strong> 可以正常填写 IP 和端口。</p><p>需要注意的是：</p><p>若 <code>IP 地址</code> 与 <code>端口</code> 留空，则后续 <code>网络模式</code> 仅支持选择：<code>无端口映射模式</code></p><p>若填写了 IP 与端口，则后续 <code>网络模式</code> 与标准模式一致，可选择全部类型。</p><p><img src="'+t+'" alt="" loading="lazy"></p><p>点击保存后，可以在页面中的 <code>连接配置</code> 区域看到生成安装命令的按钮。</p><p>需要特别注意：</p><ul><li><p>节点保存后，系统会生成并写死当前节点的 <code>Token</code></p></li><li><p>Token 无法单独刷新或修改</p></li><li><p>若 Token 泄露，只能：</p><ol><li>删除当前节点</li><li>重新新增节点</li><li>重新填写所有配置</li></ol></li></ul><p>因此请务必妥善保管 Token，避免泄露。</p><p><img src="'+o+'" alt="" loading="lazy"></p><p>点击生成后，会得到对应的安装命令。</p><p>直接复制该命令，并在目标节点服务器上执行即可完成 Agent 安装与接入。</p><p>安装完成后，可以在当前页面下方点击 <code>检测</code> 按钮验证连接状态。</p><p><img src="'+c+'" alt="" loading="lazy"></p><p><img src="'+r+'" alt="" loading="lazy"></p><p>当检测成功后，后续的大部分配置流程与标准模式基本一致，无需额外特殊操作。</p><p><img src="'+d+'" alt="" loading="lazy"></p><p>仅在 <code>网络模式</code> 配置部分，本地节点需要特别注意：</p><p>请务必选择<code>无端口映射</code></p><p>这样后续即可通过管理员后台的<code>端口管理</code></p><p>页面，手动执行<code>添加端口</code></p><p>将节点内部端口映射（内网穿透）到主控服务器的 IPv4 地址上供外部访问。</p><p><img src="'+u+`" alt="" loading="lazy"></p><p>在手动添加端口映射时，请选择：</p><p><code>控制端转发（内网穿透）</code></p><p>对于非必填项，可以直接留空，系统会自动筛选并分配主控服务器可用端口。</p><h3 id="主控部署要求" tabindex="-1">主控部署要求 <a class="header-anchor" href="#主控部署要求" aria-label="Permalink to &quot;主控部署要求&quot;">​</a></h3><p>由于内网穿透功能需要主控具备对宿主机网络与防火墙的控制能力，因此主控必须满足以下条件</p><ul><li><p>使用二者之一：</p><ul><li><code>脚本部署</code></li><li><code>裸机编译部署</code></li></ul></li><li><p>部署于：</p><ul><li>拥有独立公网 IPv4 地址的 Linux 服务器</li></ul></li><li><p>必须具备：</p><ul><li><code>Root 权限</code></li></ul></li></ul><p>不支持以下部署方式</p><ul><li><code>Docker</code></li><li><code>Docker Compose</code></li><li>非 Linux 系统</li></ul><p>否则将无法正常使用内网穿透相关功能。</p><h3 id="内网穿透功能说明" tabindex="-1">内网穿透功能说明 <a class="header-anchor" href="#内网穿透功能说明" aria-label="Permalink to &quot;内网穿透功能说明&quot;">​</a></h3><p><code>内穿端口</code> 功能：</p><ul><li><p><strong>仅支持 Agent 模式纳管的节点</strong></p></li><li><p>通过：</p><ul><li><code>WS/WSS</code></li><li>WebSocket 隧道转发实现</li></ul></li></ul><p>因此在配置反向代理时，请务必确保：</p><ul><li><p>已正确配置协议转发支持：</p><ul><li><code>WS</code></li><li><code>WSS</code></li></ul></li></ul><p>否则内网穿透将无法正常工作。</p><h4 id="安全建议" tabindex="-1">安全建议 <a class="header-anchor" href="#安全建议" aria-label="Permalink to &quot;安全建议&quot;">​</a></h4><p>如果被纳管的节点存在：</p><ul><li>防探测</li><li>防封禁</li><li>隧道保密</li></ul><p>等需求，强烈建议：</p><ol><li>为主控绑定域名</li><li>配置 HTTPS</li><li>纳管节点时使用<code>WSS 协议</code>而不要使用<code>WS 协议</code></li></ol><p>这样可以有效降低隧道被识别、探测或封禁的风险。</p><h4 id="版本更新说明" tabindex="-1">版本更新说明 <a class="header-anchor" href="#版本更新说明" aria-label="Permalink to &quot;版本更新说明&quot;">​</a></h4><p>当主控版本更新后，请务必同步更新节点侧 Agent。</p><p>更新过程中使用<code>source</code>为<code>controller</code>，将直接从主控特定路径下载脚本和agent所需的文件。</p><h2 id="使用lxd-incus开设共享gpu设备的容器" tabindex="-1">使用LXD/INCUS开设共享GPU设备的容器 <a class="header-anchor" href="#使用lxd-incus开设共享gpu设备的容器" aria-label="Permalink to &quot;使用LXD/INCUS开设共享GPU设备的容器&quot;">​</a></h2><p>对于需要共享GPU设备的节点，务必确保纳管节点前节点本身已安装号对应的显卡驱动，且该显卡本身的命令执行无误，比如</p><div class="language-shell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nvidia-smi</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>要确保显示类似</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>root@a12-ThinkStation-P620:/root/sharefile# nvidia-smi</span></span>
<span class="line"><span>Sat May 16 20:23:07 2026       </span></span>
<span class="line"><span>+---------------------------------------------------------------------------------------+</span></span>
<span class="line"><span>| NVIDIA-SMI 535.171.04             Driver Version: 535.171.04   CUDA Version: 12.2     |</span></span>
<span class="line"><span>|-----------------------------------------+----------------------+----------------------+</span></span>
<span class="line"><span>| GPU  Name                 Persistence-M | Bus-Id        Disp.A | Volatile Uncorr. ECC |</span></span>
<span class="line"><span>| Fan  Temp   Perf          Pwr:Usage/Cap |         Memory-Usage | GPU-Util  Compute M. |</span></span>
<span class="line"><span>|                                         |                      |               MIG M. |</span></span>
<span class="line"><span>|=========================================+======================+======================|</span></span>
<span class="line"><span>|   0  NVIDIA RTX A6000               Off | 00000000:61:00.0 Off |                  Off |</span></span>
<span class="line"><span>| 30%   42C    P0              83W / 300W |      0MiB / 49140MiB |      1%      Default |</span></span>
<span class="line"><span>|                                         |                      |                  N/A |</span></span>
<span class="line"><span>+-----------------------------------------+----------------------+----------------------+</span></span>
<span class="line"><span>                                                                                         </span></span>
<span class="line"><span>+---------------------------------------------------------------------------------------+</span></span>
<span class="line"><span>| Processes:                                                                            |</span></span>
<span class="line"><span>|  GPU   GI   CI        PID   Type   Process name                            GPU Memory |</span></span>
<span class="line"><span>|        ID   ID                                                             Usage      |</span></span>
<span class="line"><span>|=======================================================================================|</span></span>
<span class="line"><span>|  No running processes found                                                           |</span></span>
<span class="line"><span>+---------------------------------------------------------------------------------------+</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br></div></div><p>只有宿主机安装好了驱动才能进行容器化共享GPU资源。</p><p>然后需要通过本教程中的Incus/Lxd的教程，进行好本地环境的安装，安装完毕后，通过主控的agent模式纳管完毕且执行健康检测无误后，才进行后续的操作。</p><p>推荐开启节点仅兑换码兑换模式，通过管理员的兑换码页面选择GPU设备创建容器。</p><p><img src="`+m+'" alt="" loading="lazy"></p><p>创建成功后，切换为管理员的普通用户视图兑换掉，然后回到管理员视图，去端口管理页面进行容器的端口内穿，方便直接通过web的ssh进行连接配置。</p><p><img src="'+g+'" alt="" loading="lazy"></p><p>添加成功后，可以直接通过web的ssh进行连接操控本地的这个新容器了。</p><p>进入容器后，需要安装对应的和外部宿主机一样的驱动版本，只不过这次安装的时候，要确保不要加载进入内核，添加命令参数<code>--no-kernel-module</code>。</p><p>具体如何找驱动安装驱动，详见 <a href="https://www.spiritysdx.top/20240513/#%E5%AE%B9%E5%99%A8%E5%86%85%E5%AE%89%E8%A3%85gpu%E9%A9%B1%E5%8A%A8" target="_blank" rel="noreferrer">https://www.spiritysdx.top/20240513/#容器内安装gpu驱动</a> 如何进行的驱动安装。</p><p>安装完毕后，容器内也可以执行<code>nvidia-smi</code>得到输出，证明GPU已共享使用了。</p><p><img src="'+b+'" alt="" loading="lazy"></p><p>那此时就可以停止这个容器，以此为母本，使用兑换码的批量开设容器的复制模式，设置此容器为源容器进行复制开设新容器了。</p>',74)]))}const A=a(h,[["render",_]]);export{S as __pageData,A as default};
